module d_ff_async_reset (
    input D, RESET_B, CLK,
    output Q
);

reg Q;

  wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @(posedge CLK, negedge RESET_B or posedge dbg_halt) begin
    if (!RESET_B) begin
        Q <= 0;
    end else begin
        Q <= D;
    end
end

endmodule
